mapper.select:
select e.id,e.username,e.name,e.status, r.name as role_name from employee e left join employee_role er ON e.id=er.employee_id left join role r ON er.role_id=r.id
and e.name like concat('%',#{name},'%') and e.username like concat('%',#{username},'%') and e.status=#{status}
order by e.id ASC

select role_id
from employee_role
where employee_id = #{employeeId}

select count(*)
from employee_role
where role_id = #{id}

mapper.insert:
insert into employee_role(
    employee_id, role_id
) VALUES(#{id}, #{roleId})

mapper.update:
update employee
name=#{name}, username=#{username}, password=#{password}, openid=#{openid}, login_type=#{loginType}, status=#{status}, update_time= #{updateTime}, update_user= #{updateUser},
where id=#{id}

update employee_role
set role_id= #{roleId}
where employee_id= #{employeeId}
